package com.company.supervision.api;import com.company.supervision.application.identity.AuthService;import com.company.supervision.application.organization.WecomIntegrationService;import com.company.supervision.entity.dto.ApiResult;import com.company.supervision.infrastructure.security.AuthInterceptor;import jakarta.servlet.http.HttpServletRequest;import org.springframework.web.bind.annotation.*;import java.util.*;
@RestController public class WecomSettingsController{private final WecomIntegrationService s;public WecomSettingsController(WecomIntegrationService s){this.s=s;}@GetMapping("/settings/wecom")public ApiResult<Map<String,Object>>get(){return ApiResult.ok(s.getConfig());}@PutMapping("/settings/wecom")public ApiResult<Void>save(@RequestBody Map<String,Object>m){s.save(m);return ApiResult.ok(null);}@PostMapping("/settings/wecom/verify")public ApiResult<Map<String,Object>>verify(){return ApiResult.ok(s.verify());}@PostMapping("/wecom/sync")public ApiResult<Map<String,Object>>sync(HttpServletRequest r){AuthService.SessionInfo i=(AuthService.SessionInfo)r.getAttribute(AuthInterceptor.SESSION_ATTRIBUTE);return ApiResult.ok(s.sync(i.getAccountId()));}@GetMapping("/wecom/sync-logs")public ApiResult<?>logs(){return ApiResult.ok(s.syncLogs());}@GetMapping("/departments/tree")public ApiResult<?>deps(){return ApiResult.ok(s.departmentTree());}@GetMapping("/persons")public ApiResult<?>persons(@RequestParam(required=false)String name){return ApiResult.ok(s.people(name));}}